/**
 * @param {number[]} numbers
 * @param {number} target
 * @return {number[]}
 */
var twoSum = function (numbers = [2, 7, 11, 15], target = 9) {
    let i = 0, j = numbers.length - 1;

    while (i < j) {
        let sum = numbers[i] + numbers[j];
        if (sum === target) {
            return [i + 1, j + 1];
        } else if (sum > target) j--;
        else i++
    }
};

